package utils;
import org.apache.poi.ss.usermodel.*;import java.io.InputStream;import java.util.*;
public final class ExcelUtil { private ExcelUtil(){} public static Object[][] readSheet(String resourcePath,String sheetName){ try(InputStream in=Thread.currentThread().getContextClassLoader().getResourceAsStream(resourcePath); Workbook wb=WorkbookFactory.create(in)){ Sheet s=wb.getSheet(sheetName); Row header=s.getRow(0); int rows=s.getLastRowNum(), cols=header.getLastCellNum(); Object[][] data=new Object[rows][1]; for(int i=1;i<=rows;i++){ Map<String,String> row=new LinkedHashMap<>(); for(int j=0;j<cols;j++){ row.put(header.getCell(j).getStringCellValue(), new DataFormatter().formatCellValue(s.getRow(i).getCell(j))); } data[i-1][0]=row; } return data; }catch(Exception e){ throw new RuntimeException(e);} } }
